CREATE TABLE beneficial_owner (legal_entity_party_id UUID NOT NULL REFERENCES legal_entity(party_id), owner_party_id UUID NOT NULL REFERENCES party(party_id), ownership_percent NUMERIC(5,2) NOT NULL CHECK (ownership_percent BETWEEN 0 AND 100), control_by_other_means BOOLEAN NOT NULL DEFAULT false, valid_from TIMESTAMPTZ NOT NULL DEFAULT now(), valid_until TIMESTAMPTZ, PRIMARY KEY (legal_entity_party_id, owner_party_id, valid_from));
